5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
17	
18	const COMPONENT_TYPES = new Set(["rune"]);
19	const BLOCK_BASE_PREMIUM = 60;
20	
21	const basePremiumForItems = (items: Item[]): number => {
22	  // Detect: all items same component type and exactly 3 → block
23	  if (items.length === 3 && items.every((i) => COMPONENT_TYPES.has(i.type)) && items.every((i) => i.type === items[0].type)) {
24	    return BLOCK_BASE_PREMIUM;
25	  }
26	  return items.reduce((sum, item) => sum + basePremiumOf(item), 0);
27	};
28	
29	const quotePremium = (step: Step): number => {
30	  const base = basePremiumForItems(step.items);
31	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
32	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
33	};
34	
35	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => ({
36	  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
37	});
